UPDATE TUSER
SET    PASSWD   = #{userdto.passwd},
       USERNAME = #{userdto.username},
       EMAIL    = #{userdto.email}
WHERE  USERID   = #{userdto.userid} 
  AND  PASSWD   = #{oldpwd}

UPDATE TUSER
SET    PASSWD   = #{passwd},
       USERNAME = #{username},
       EMAIL    = #{email}
WHERE  USERID   = #{userid} 
  AND  PASSWD   = #{oldpwd}
